    const A=XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]],{header:1,defval:null});
    const need={kode:["kode ahs","kode_ahs","kodeahs","kode analisa","kode"],nama:["nama ahs","nama analisa","nama","uraian"],unit:["unit","satuan"],grup:["kelompok","grup","group","header"],sd:["kode sd","kode_sd","sumber daya","resource","sd"],koef:["koef","koefisien","coef","qty"]};
    const h=findHdr(A,need);if(!h){alert("Header tidak ketemu. Kolom: Kode AHS, Nama AHS, Unit, Kelompok, Kode SD, Koef.");return;}
    const {idx}=h;const nahs={},nn={},nu={};let cur=null;
